```rust
pub fn collect_values(root, pointer, property_name) -> Vec<ValueSuggestion> {
    let mut visited = HashSet::new();
    let Some(object_schema) = resolve_subschema(root, root, pointer, &mut visited, 0) else {
        return vec![];
    };

    let mut suggestions = Vec::new();
    let mut seen = HashSet::new();
    collect_values_in_object(root, object_schema, property_name, &mut suggestions, &mut seen, 0);
    suggestions
}

fn collect_values_in_object(root, schema, property_name, suggestions, seen, depth) {
    if depth > MAX_SCHEMA_DEPTH { return; }
    let mut visited = HashSet::new();
    let Some(schema) = follow_ref(root, schema, &mut visited) else { return; };

    // If this object defines the property, collect values from its value schema.
    if let Some(prop_schema) = schema.get("properties").and_then(|p| p.get(property_name)) {
        collect_values_from_value(root, prop_schema, suggestions, seen, depth);
    }

    // Recurse into composition.
    for key in ["allOf", "anyOf", "oneOf"] {
        if let Some(branches) = schema.get(key).and_then(|v| v.as_array()) {
            for branch in branches {
                collect_values_in_object(root, branch, property_name, suggestions, seen, depth + 1);
            }
        }
    }
}

fn collect_values_from_value(root, schema, suggestions, seen, depth) {
    if depth > MAX_SCHEMA_DEPTH { return; }
    let mut visited = HashSet::new();
    let Some(schema) = follow_ref(root, schema, &mut visited) else { return; };

    // const
    if let Some(const_val) = schema.get("const") {
        push_dedup(seen, suggestions, ValueSuggestion::Const(const_val.clone()), ...);
    }
    // enum
    if let Some(enum_vals) = schema.get("enum").and_then(|v| v.as_array()) {
        for val in enum_vals { push_dedup(...Enum(val)...); }
    }
    // type
    for ty in schema_types(schema) {
        match ty.as_str() {
            "boolean" => push_dedup(...Boolean...),
            "null" => push_dedup(...Null...),
            _ => {}
        }
    }
    // Recurse into composition within the value schema.
    for key in ["allOf", "anyOf", "oneOf"] {
        if let Some(branches) = schema.get(key).and_then(|v| v.as_array()) {
            for branch in branches {
                collect_values_from_value(root, branch, suggestions, seen, depth + 1);
            }
        }
    }
}
