/// Extract the `type` keyword as a list of type strings, handling both the
/// single-string (`"type": "string"`) and array (`"type": ["string", "null"]`)
/// forms used for nullable types. Returns an empty vec if `type` is absent.
fn schema_types(schema: &serde_json::Value) -> Vec<String> {
    match schema.get("type") {
        Some(serde_json::Value::String(s)) => vec![s.clone()],
        Some(serde_json::Value::Array(arr)) => arr
            .iter()
            .filter_map(|v| v.as_str().map(|s| s.to_string()))
            .collect(),
        _ => Vec::new(),
    }
}

