/// Collect possible value suggestions for a property at the given pointer path.
///
/// Navigates to the object at `pointer`, then gathers the value schema for
/// `property_name` across `allOf`/`anyOf`/`oneOf` branches. For each value
/// schema it inspects `const`, `enum`, and `type` (including nullable `type`
/// arrays), recursing into further composed branches. Duplicate suggestions are
/// suppressed.
pub fn collect_values(
    root: &serde_json::Value,
    pointer: &[String],
    property_name: &str,
) -> Vec<ValueSuggestion> {
    let mut visited = HashSet::new();
    let Some(object_schema) = resolve_subschema(root, root, pointer, &mut visited, 0) else {
        return vec![];
    };

    let mut suggestions: Vec<ValueSuggestion> = Vec::new();
    let mut seen: HashSet<String> = HashSet::new();
    collect_values_for_property(
        root,
        object_schema,
        property_name,
        &mut suggestions,
        &mut seen,
        0,
    );
    suggestions
}

/// Walk an object schema (and its `allOf`/`anyOf`/`oneOf` branches) to find
/// every subschema declared for `property_name`, collecting value suggestions
/// from each.
fn collect_values_for_property(
    root: &serde_json::Value,
    schema: &serde_json::Value,
    property_name: &str,
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<String>,
    depth: usize,
) {
    if depth > MAX_SCHEMA_DEPTH {
        return;
    }

    let mut visited = HashSet::new();
    let Some(schema) = follow_ref(root, schema, &mut visited) else {
        return;
    };

    if let Some(prop_schema) = schema
        .get("properties")
        .and_then(|p| p.get(property_name))
    {
        collect_values_from_schema(root, prop_schema, suggestions, seen, depth);
    }

    for key in ["allOf", "anyOf", "oneOf"] {
        if let Some(branches) = schema.get(key).and_then(|v| v.as_array()) {
            for branch in branches {
                collect_values_for_property(
                    root,
                    branch,
                    property_name,
                    suggestions,
                    seen,
                    depth + 1,
                );
            }
        }
    }
}

/// Collect value suggestions (`const`/`enum`/`type`) from a single value schema,
/// recursing into `allOf`/`anyOf`/`oneOf` branches. Duplicates are suppressed
/// via `seen`.
fn collect_values_from_schema(
    root: &serde_json::Value,
    schema: &serde_json::Value,
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<String>,
    depth: usize,
) {
    if depth > MAX_SCHEMA_DEPTH {
        return;
    }

    let mut visited = HashSet::new();
    let Some(schema) = follow_ref(root, schema, &mut visited) else {
        return;
    };

    if let Some(const_val) = schema.get("const") {
        push_value_suggestion(seen, suggestions, ValueSuggestion::Const(const_val.clone()));
    }

    if let Some(enum_vals) = schema.get("enum").and_then(|v| v.as_array()) {
        for val in enum_vals {
            push_value_suggestion(seen, suggestions, ValueSuggestion::Enum(val.clone()));
        }
    }

    // `type` may be a single string or an array (nullable forms like
    // `["string", "null"]`).
    for ty in schema_types(schema) {
        match ty.as_str() {
            "boolean" => push_value_suggestion(seen, suggestions, ValueSuggestion::Boolean),
            "null" => push_value_suggestion(seen, suggestions, ValueSuggestion::Null),
            _ => {}
        }
    }

    for key in ["allOf", "anyOf", "oneOf"] {
        if let Some(branches) = schema.get(key).and_then(|v| v.as_array()) {
            for branch in branches {
                collect_values_from_schema(root, branch, suggestions, seen, depth + 1);
            }
        }
    }
}

/// Push a suggestion unless an equivalent one has already been collected.
fn push_value_suggestion(
    seen: &mut HashSet<String>,
    suggestions: &mut Vec<ValueSuggestion>,
    suggestion: ValueSuggestion,
) {
    if seen.insert(suggestion.dedup_key()) {
        suggestions.push(suggestion);
    }
}

