/// Possible value suggestions for a property.
#[derive(Debug, Clone)]
pub enum ValueSuggestion {
    /// A value from a schema `enum` array.
    Enum(serde_json::Value),
    /// A value from a schema `const`.
    Const(serde_json::Value),
    /// Suggests `true` and `false`.
    Boolean,
    /// Suggests `null`.
    Null,
}

impl ValueSuggestion {
    /// Stable key used to suppress duplicate suggestions. `Enum` and `Const`
    /// holding the same value share a key so the user never sees two identical
    /// value entries.
    fn dedup_key(&self) -> String {
        match self {
            ValueSuggestion::Enum(v) | ValueSuggestion::Const(v) => {
                format!("value:{v}")
            }
            ValueSuggestion::Boolean => "boolean".to_string(),
            ValueSuggestion::Null => "null".to_string(),
        }
    }
}

