/// Return a snippet placeholder appropriate for the given JSON schema type.
///
/// `schema_type` may be a single type (`"string"`) or a pipe-joined nullable
/// form (`"string|null"`). The first concrete type with a placeholder wins so
/// a nullable field inserts a real value (e.g. `"$1"`) rather than `null`.
fn snippet_for_type(schema_type: Option<&str>) -> &'static str {
    let types: Vec<&str> = schema_type
        .map(|t| t.split('|').collect())
        .unwrap_or_default();
    for ty in &types {
        match *ty {
            "string" => return "\"$1\"",
            "number" | "integer" => return "${1:0}",
            "boolean" => return "${1:false}",
            "object" => return "{$1}",
            "array" => return "[$1]",
            _ => {}
        }
    }
    if types.iter().any(|t| *t == "null") {
        return "null";
    }
    "$0"
}

