#[test]
fn collect_values_no_suggestions() {
    let schema = serde_json::json!({
        "properties": {
            "name": { "type": "string" }
        }
    });
    let values = collect_values(&schema, &[], "name");
    assert!(values.is_empty());
}

#[test]
fn collect_properties_anyof_oneof_merge() {
    let schema = serde_json::json!({
        "anyOf": [
            {"properties": {"a": {"type": "string"}}, "required": ["a"]},
            {"oneOf": [
                {"properties": {"b": {"type": "number"}}},
                {"properties": {"c": {"type": "boolean"}}}
            ]}
        ],
        "properties": {"d": {"type": "string"}}
    });
    let mut names: Vec<String> = collect_properties(&schema, &[])
        .into_iter()
        .map(|p| p.name)
        .collect();
    names.sort();
    assert_eq!(names, vec!["a".to_string(), "b".into(), "c".into(), "d".into()]);
}

#[test]
fn collect_properties_nullable_type_label() {
    let schema = serde_json::json!({
        "properties": {
            "port": {"type": ["integer", "null"]},
            "name": {"type": "string"}
        }
    });
    let props = collect_properties(&schema, &[]);
    let port = props.iter().find(|p| p.name == "port").unwrap();
    assert_eq!(port.schema_type.as_deref(), Some("integer|null"));
    let name = props.iter().find(|p| p.name == "name").unwrap();
    assert_eq!(name.schema_type.as_deref(), Some("string"));
}

#[test]
fn collect_values_anyof_enum_branches() {
    // Value schema is composed: string | enum.
    let schema = serde_json::json!({
        "properties": {
            "env": {
                "anyOf": [
                    {"type": "string"},
                    {"enum": ["dev", "staging", "prod"]}
                ]
            }
        }
    });
    let values = collect_values(&schema, &[], "env");
    let labels: Vec<&serde_json::Value> = values
        .iter()
        .filter_map(|v| match v {
            ValueSuggestion::Enum(e) => Some(e),
            _ => None,
        })
        .collect();
    assert_eq!(labels.len(), 3);
    assert!(labels.contains(&&serde_json::json!("dev")));
    assert!(labels.contains(&&serde_json::json!("prod")));
}

#[test]
fn collect_values_oneof_const_dedup() {
    // Repeated const values across oneOf branches must dedupe.
    let schema = serde_json::json!({
        "properties": {
            "level": {
                "oneOf": [
                    {"const": "info"},
                    {"const": "debug"},
                    {"const": "info"}
                ]
            }
        }
    });
    let values = collect_values(&schema, &[], "level");
    assert_eq!(values.len(), 2, "expected deduped consts: {values:?}");
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Const(x) if x == "info")));
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Const(x) if x == "debug")));
}

#[test]
fn collect_values_nullable_boolean() {
    let schema = serde_json::json!({
        "properties": {
            "enabled": {"type": ["boolean", "null"]}
        }
    });
    let values = collect_values(&schema, &[], "enabled");
    assert_eq!(values.len(), 2);
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Boolean)));
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Null)));
}

#[test]
fn collect_values_nullable_string_only_null() {
    let schema = serde_json::json!({
        "properties": {
            "tag": {"type": ["string", "null"]}
        }
    });
    let values = collect_values(&schema, &[], "tag");
    assert_eq!(values.len(), 1);
    assert!(matches!(&values[0], ValueSuggestion::Null));
}

#[test]
fn collect_values_across_composed_object() {
    // The *object* is composed; the same property is described in two
    // branches with different enums — values from both must be collected.
    let schema = serde_json::json!({
        "anyOf": [
            {"properties": {"mode": {"enum": ["a", "b"]}}},
            {"properties": {"mode": {"enum": ["b", "c"]}}}
        ]
    });
    let values = collect_values(&schema, &[], "mode");
    // "b" appears in both branches and must be deduped.
    assert_eq!(values.len(), 3, "expected deduped enums: {values:?}");
}

#[test]
fn collect_values_const_and_enum_same_value_dedup() {
    let schema = serde_json::json!({
        "properties": {
            "v": {
                "anyOf": [
                    {"const": "x"},
                    {"enum": ["x", "y"]}
                ]
            }
        }
    });
    let values = collect_values(&schema, &[], "v");
    // const "x" and enum "x" collapse; only "x" and "y" remain.
    assert_eq!(values.len(), 2, "expected deduped values: {values:?}");
}

#[test]
fn resolve_subschema_anyof_branch() {
    let schema = serde_json::json!({
        "anyOf": [
            {"properties": {"x": {"title": "X"}}}
        ]
    });
    let result = resolve_subschema_at_pointer(&schema, &["x".into()]);
    assert!(result.is_some());
    assert_eq!(result.unwrap().get("title").unwrap(), "X");
}

#[test]
fn hover_anyof_property() {
    let schema = serde_json::json!({
        "anyOf": [
            {"properties": {"name": {"title": "Name", "description": "via anyOf"}}}
        ]
    });
    let result = lookup_hover_content(&schema, &["name".into()]);
    assert_eq!(result, Some("**Name**\n\nvia anyOf".into()));
}

#[test]
fn collect_values_nested_nullable_object_property() {
    // Nested object whose own schema is composed and nullable properties.
    let schema = serde_json::json!({
        "properties": {
            "server": {
                "allOf": [
                    {"properties": {"retries": {"type": ["integer", "null"]}}}
                ]
            }
        }
    });
    let values = collect_values(&schema, &["server".into()], "retries");
    // integer gives no value suggestion; null gives Null.
    assert_eq!(values.len(), 1);
    assert!(matches!(&values[0], ValueSuggestion::Null));
}

