/// `allOf` + `$ref` should merge base properties with the extending schema's
/// own properties, all offered as completable keys.
#[tokio::test]
async fn completion_allof_ref_merges_properties() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_composed_schema("");
    let uri = composed_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let cursor_col = (content.len() - 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let names = labels(&result);
    // From the allOf -> $ref BaseConfig.
    assert!(
        names.contains(&"service".to_string()),
        "expected base 'service' from allOf/$ref, got: {names:?}"
    );
    assert!(
        names.contains(&"replicas".to_string()),
        "expected base 'replicas' from allOf/$ref, got: {names:?}"
    );
    // From the extending schema's own properties.
    assert!(names.contains(&"environment".to_string()), "got: {names:?}");
    assert!(names.contains(&"logLevel".to_string()), "got: {names:?}");
    assert!(names.contains(&"enabled".to_string()), "got: {names:?}");
    assert!(names.contains(&"notes".to_string()), "got: {names:?}");
    assert!(
        names.contains(&"healthcheck".to_string()),
        "got: {names:?}"
    );
    // No duplicate "service" from merging.
    let service_count = names.iter().filter(|n| *n == "service").count();
    assert_eq!(service_count, 1, "expected no duplicate 'service'");
}

/// Nullable (`type: ["integer","null"]`) property detail reports the null option.
#[tokio::test]
async fn completion_nullable_property_detail() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_composed_schema("");
    let uri = composed_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let cursor_col = (content.len() - 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let items = result["items"].as_array().unwrap();
    let replicas = items.iter().find(|i| i["label"] == "replicas").unwrap();
    let detail = replicas["detail"].as_str().unwrap();
    assert!(
        detail.contains("null"),
        "expected nullable type in detail for 'replicas', got: {detail}"
    );
}

/// `anyOf` value branches: a `string | enum` property completes with the enum.
#[tokio::test]
async fn completion_anyof_enum_values() {
    let mut client = TestClient::new();
    client.initialize().await;

    // {"$schema": "...", "environment": null}
    let content = doc_with_composed_schema(r#""environment": null"#);
    let uri = composed_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let needle = "\"environment\": ";
    let idx = content.find(needle).unwrap() + needle.len();
    let result = client.completion(&uri, 0, idx as u32).await;

    let names = labels(&result);
    assert!(
        names.contains(&r#""dev""#.to_string()),
        "expected '\"dev\"' from anyOf enum, got: {names:?}"
    );
    assert!(
        names.contains(&r#""staging""#.to_string()),
        "expected '\"staging\"' from anyOf enum, got: {names:?}"
    );
    assert!(
        names.contains(&r#""prod""#.to_string()),
        "expected '\"prod\"' from anyOf enum, got: {names:?}"
    );
    // No duplicates from the branches.
    let unique: std::collections::HashSet<&str> =
        names.iter().map(String::as_str).collect();
    assert_eq!(unique.len(), names.len(), "duplicate value labels: {names:?}");
}

/// `oneOf` const branches collapse duplicate consts into single suggestions.
#[tokio::test]
async fn completion_oneof_const_dedup_values() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_composed_schema(r#""logLevel": null"#);
    let uri = composed_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let needle = "\"logLevel\": ";
    let idx = content.find(needle).unwrap() + needle.len();
    let result = client.completion(&uri, 0, idx as u32).await;

    let names = labels(&result);
    assert!(
        names.contains(&r#""info""#.to_string()),
        "expected '\"info\"' from oneOf const, got: {names:?}"
    );
    assert!(
        names.contains(&r#""debug""#.to_string()),
        "expected '\"debug\"' from oneOf const, got: {names:?}"
    );
    // "info" appears in two oneOf branches but must be suggested once.
    let info_count = names.iter().filter(|n| *n == "\"info\"").count();
    assert_eq!(info_count, 1, "expected deduped '\"info\"': {names:?}");
}

/// Nullable boolean: `type: ["boolean","null"]` completes true/false/null.
#[tokio::test]
async fn completion_nullable_boolean_values() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_composed_schema(r#""enabled": null"#);
    let uri = composed_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let needle = "\"enabled\": ";
    let idx = content.find(needle).unwrap() + needle.len();
    let result = client.completion(&uri, 0, idx as u32).await;

    let names = labels(&result);
    assert!(names.contains(&"true".to_string()), "got: {names:?}");
    assert!(names.contains(&"false".to_string()), "got: {names:?}");
    assert!(names.contains(&"null".to_string()), "got: {names:?}");
}

/// Nullable string: `type: ["string","null"]` offers `null` only (no string
/// value suggestion).
#[tokio::test]
async fn completion_nullable_string_value_is_null_only() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_composed_schema(r#""notes": null"#);
    let uri = composed_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let needle = "\"notes\": ";
