/// Nullable property inside a nested object.
#[tokio::test]
async fn completion_nested_nullable_value() {
    let mut client = TestClient::new();
    client.initialize().await;

    // {"$schema": "...", "healthcheck": {"port": null}}
    let content = doc_with_composed_schema(r#""healthcheck": {"port": null}"#);
