/// With snippet support, a nullable property's text edit uses the concrete type
/// placeholder rather than `null`.
#[tokio::test]
async fn completion_nullable_property_snippet_uses_concrete_type() {
    let mut client = TestClient::new();
    client
        .initialize_with_params(serde_json::json!({
